	input [4:1] x,
	output reg obf_j);always_comb begin
		case (x) 
			4'h0: obf_j = 1;
			4'h1: obf_j = 1;
			4'h2: obf_j = 0;
			4'h3: obf_j = 1;
			4'h4: obf_j = 1;
			4'h5: obf_j = 0;
			4'h6: obf_j = 0;
			4'h7: obf_j = 1;
			4'h8: obf_j = 1;
			4'h9: obf_j = 0;
			4'ha: obf_j = 0;
			4'hb: obf_j = 0;
			4'hc: obf_j = 0;
			4'hd: obf_j = 0;
			4'he: obf_j = 1;
			4'hf: obf_j = 1;
		endcase
	end

endmodule
